import json, re

        def evaluate_exact(actual: str, expected: str) -> dict:
            """Check if actual matches expected (case-insensitive, stripped)."""
            actual_clean = actual.strip().lower()
            expected_clean = expected.strip().lower()
            exact = actual_clean == expected_clean
            # Also try extracting numbers for numeric answers
            actual_nums = re.findall(r'-?\d+\.?\d*', actual)
            expected_nums = re.findall(r'-?\d+\.?\d*', expected)
            numeric_match = bool(actual_nums and expected_nums
                                 and actual_nums[0] == expected_nums[0])
            return {
                "pass": exact or numeric_match,
                "exact_match": exact,
                "numeric_match": numeric_match,
                "actual": actual[:200],
                "expected": expected,
            }

        def evaluate_contains(actual: str, required_substrings: list[str]) -> dict:
            """Check that actual contains all required substrings."""
            missing = [s for s in required_substrings if s.lower() not in actual.lower()]
            return {
                "pass": len(missing) == 0,
                "missing": missing,
                "actual": actual[:200],
            }

        def evaluate_json_schema(actual: str, schema: dict) -> dict:
            """Check that actual is valid JSON matching the schema."""
            try:
                from jsonschema import validate, ValidationError
                parsed = json.loads(actual)
                validate(instance=parsed, schema=schema)
                return {"pass": True, "parsed": parsed}
            except json.JSONDecodeError as e:
                return {"pass": False, "error": f"Invalid JSON: {e}"}
            except Exception as e:
                return {"pass": False, "error": str(e)}

        def evaluate_code(generated_code: str, test_cases: list[dict]) -> dict:
            """
            Execute generated code with test cases and check outputs.
            Each test_case: {'args': [...], 'expected': value}
            """
            results = []
            namespace = {}
            try:
                exec(generated_code, namespace)
            except Exception as e:
                return {"pass": False, "error": f"Code failed to compile: {e}", "results": []}

            func = next((v for v in namespace.values() if callable(v) and not v.__name__.startswith("_")), None)
            if not func:
                return {"pass": False, "error": "No callable function found", "results": []}

            for tc in test_cases:
                try:
                    actual = func(*tc["args"])
                    passed = actual == tc["expected"]
                    results.append({"args": tc["args"], "expected": tc["expected"],
                                    "actual": actual, "pass": passed})
                except Exception as e:
                    results.append({"args": tc["args"], "error": str(e), "pass": False})

            all_pass = all(r["pass"] for r in results)
            return {"pass": all_pass, "results": results}

        # Example usage
        result = evaluate_code(
            generated_code="""
def fibonacci(n):
    if n <= 1: return n
    return fibonacci(n - 1) + fibonacci(n - 2)
""",
            test_cases=[
                {"args": [0], "expected": 0},
                {"args": [1], "expected": 1},
                {"args": [10], "expected": 55},
                {"args": [15], "expected": 610},
            ],
        )
        print(result)
        # {'pass': True, 'results': [{'args': [0], 'expected': 0, 'actual': 0, 'pass': True}, ...]}
